#version 330 core

in vec3 vNormal;
in vec3 vFragPos;
in vec3 vColor;
in vec2 vTexcoord;

uniform vec3 viewPos;
uniform bool useTexture;
uniform sampler2D texture0;
uniform bool useVertexColor;

uniform vec3 materialAmbient;
uniform vec3 materialDiffuse;
uniform vec3 materialSpecular;
uniform float materialShininess;

uniform vec3 light1Direction;
uniform vec3 light1Ambient;
uniform vec3 light1Diffuse;
uniform vec3 light1Specular;

uniform vec3 light2Position;
uniform vec3 light2Ambient;
uniform vec3 light2Diffuse;
uniform vec3 light2Specular;
uniform float light2Constant;
uniform float light2Linear;
uniform float light2Quadratic;

out vec4 outColor;

vec3 calcDirectionalLight(vec3 normal, vec3 viewDir, vec3 lightDir, vec3 ambient, vec3 diffuse, vec3 specular) {
    vec3 n = normalize(normal);
    vec3 l = normalize(-lightDir);

    vec3 result = ambient * materialAmbient;

    float diff = max(dot(n, l), 0.0);
    result += diff * diffuse * materialDiffuse;

    vec3 reflectDir = reflect(-l, n);
    float spec = pow(max(dot(viewDir, reflectDir), 0.0), materialShininess);
    result += spec * specular * materialSpecular;

    return result;
}

vec3 calcPointLight(vec3 normal, vec3 viewDir, vec3 fragPos, vec3 lightPos, vec3 ambient, vec3 diffuse, vec3 specular, float constant, float linear, float quadratic) {
    vec3 n = normalize(normal);
    vec3 lightDir = lightPos - fragPos;
    float distance = length(lightDir);
    lightDir = normalize(lightDir);

    float attenuation = 1.0 / (constant + linear * distance + quadratic * distance * distance);

    vec3 result = ambient * materialAmbient;

    float diff = max(dot(n, lightDir), 0.0);
    result += diff * diffuse * materialDiffuse;

    vec3 reflectDir = reflect(-lightDir, n);
    float spec = pow(max(dot(viewDir, reflectDir), 0.0), materialShininess);
    result += spec * specular * materialSpecular;

    return result * attenuation;
}

void main() {
    vec3 baseColor;
    if (useTexture) {
        baseColor = vec3(texture(texture0, vTexcoord));
    } else if (useVertexColor) {
        baseColor = vColor;
    } else {
        baseColor = materialDiffuse;
    }

    vec3 norm = normalize(vNormal);
    vec3 viewDir = normalize(viewPos - vFragPos);

    vec3 result = vec3(0.0);

    result += calcDirectionalLight(norm, viewDir, light1Direction, light1Ambient, light1Diffuse, light1Specular);

    result += calcPointLight(norm, viewDir, vFragPos, light2Position, light2Ambient, light2Diffuse, light2Specular, light2Constant, light2Linear, light2Quadratic);

    result *= baseColor;

    outColor = vec4(result, 1.0);
}

